import bisect

def minSubArrayLen(self, target, nums):
    n = len(nums)
    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i+1] = prefix[i] + nums[i]

    min_len = float('inf')
    for i in range(n):
        needed = target + prefix[i]
        j = bisect.bisect_left(prefix, needed)
        if j <= n:
            min_len = min(min_len, j - i)

    return 0 if min_len == float('inf') else min_len
